package com.raonmate.backend.budget.api; import com.raonmate.backend.budget.domain.BudgetPlan; import java.math.BigDecimal; import java.time.Instant; import java.util.*; public record BudgetResponse(UUID id,UUID workshopId,List<Item> items,BigDecimal totalAmount,BigDecimal limitAmount,BigDecimal remainingAmount,Instant updatedAt){public static BudgetResponse from(BudgetPlan p){var items=p.getItems().stream().map(i->new Item(i.getCategory(),i.getName(),i.getAmount(),i.getNote())).toList();BigDecimal total=items.stream().map(Item::amount).reduce(BigDecimal.ZERO,BigDecimal::add);BigDecimal limit=p.getWorkshop().getBudgetPerPerson()==null?BigDecimal.ZERO:p.getWorkshop().getBudgetPerPerson().multiply(BigDecimal.valueOf(p.getWorkshop().getExpectedParticipants()));return new BudgetResponse(p.getId(),p.getWorkshop().getId(),items,total,limit,limit.subtract(total),p.getUpdatedAt());}public record Item(String category,String name,BigDecimal amount,String note){}}
